# Write helper: mcts/agent.py
mcts_agent_py_content = 'import os\nimport random\n\nimport torch\n\ntry:\n    from base_agent import BaseAgent\nexcept ImportError:\n    from agents.base import BaseAgent\nfrom cg.api import Observation, search_begin, search_end, search_step, to_observation_class\n\nfrom .encoding import encode_actions, encode_state\nfrom .model import MODEL_ARGS, PolicyValueNet, model_args_from_state_dict\nfrom .opponent import infer_opponent_hidden_cards\nfrom .search import MAX_ACTION_COMBINATIONS, Evaluator, create_node, evaluate_position, select_child\n\n\ndef _nn_evaluator(model: PolicyValueNet, your_deck: list[int]) -> Evaluator:\n    """Build the inference-time `evaluate` closure for `create_node`."""\n\n    def evaluate(obs: Observation, actions: list[list[int]]) -> tuple[float, list[float]]:\n        sv_enc = encode_state(obs, your_deck)\n        sv_dec = encode_actions(obs, actions)\n        return evaluate_position(sv_enc, sv_dec, model)\n\n    return evaluate\n\n\nclass MCTSTransformerAgent(BaseAgent):\n    """MCTS player backed by a transformer policy/value network.\n\n    ``MCTS_DEVICE`` forces cpu/cuda/mps, ``MCTS_SEARCH_COUNT`` controls inference\n    simulations, ``MCTS_MODEL_PATH`` selects the singleton wrapper\'s checkpoint,\n    and ``MCTS_DECK`` selects its deck CSV.\n    """\n\n    def __init__(\n        self,\n        deck: list[int] | str = "abomasnow.csv",\n        model_path: str | None = None,\n        model_args: tuple[int, int, int, int, int] | None = None,\n    ) -> None:\n        # Load variant config if present\n        variant_data = {}\n        candidate_paths = [\n            os.path.join(os.path.dirname(os.path.abspath(__file__)), "variant.toml"),\n            os.path.join(os.path.dirname(os.path.abspath(__file__)), "../variant.toml"),\n            os.path.join(os.getcwd(), "variant.toml"),\n            "/kaggle_simulations/agent/variant.toml",\n        ]\n        var_path = next((p for p in candidate_paths if os.path.exists(p)), None)\n        if var_path:\n            try:\n                try:\n                    import tomllib\n                except ImportError:\n                    import tomli as tomllib  # type: ignore\n                with open(var_path, "rb") as f:\n                    variant_data = tomllib.load(f)\n                print(f"[MCTSTransformerAgent] Loaded configuration from {var_path}", flush=True)\n            except Exception as e:\n                print(f"[MCTSTransformerAgent] Error reading variant config {var_path}: {e}", flush=True)\n\n        # Resolve deck path\n        deck_to_load = deck\n        if "deck_file" in variant_data:\n            # If variant config defines a deck file, check if it exists (locally)\n            # Otherwise fall back to Kaggle\'s deck.csv or the parameter\n            comp_dir = os.path.dirname(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))\n            local_deck_path = os.path.join(comp_dir, variant_data["deck_file"])\n            if os.path.exists(local_deck_path):\n                deck_to_load = local_deck_path\n\n        self.deck = self._load_deck(deck_to_load)\n        forced = os.environ.get("MCTS_DEVICE")\n        self.device = (\n            torch.device(forced)\n            if forced\n            else torch.device(\n                "cuda" if torch.cuda.is_available() else "mps" if torch.backends.mps.is_available() else "cpu"\n            )\n        )\n        state = None\n        if model_path:\n            if not os.path.exists(model_path):\n                raise FileNotFoundError(f"[MCTSTransformerAgent] model_path not found: {model_path}")\n            state = torch.load(model_path, map_location=self.device)\n\n        # Determine model_args prioritizing: parameter -> variant.toml -> weights state_dict shapes -> default\n        self.model_args = tuple(\n            model_args\n            or variant_data.get("model_args")\n            or (model_args_from_state_dict(state) if state is not None else MODEL_ARGS)\n        )\n        self.model = PolicyValueNet(*self.model_args).to(self.device)\n        self.model.eval()\n\n        if state is not None:\n            self.model.load_state_dict(state)\n            print(f"[MCTSTransformerAgent] loaded weights from {model_path}", flush=True)\n\n        self.SEARCH_COUNT = int(os.environ.get("MCTS_SEARCH_COUNT", str(variant_data.get("search_count", 10))))\n        self.features = variant_data.get("features", {})\n        self.enable_belief_features = self.features.get("enable_belief_features", False)\n        self.num_determinizations = int(self.features.get("num_determinizations", 1))\n        self.c_puct = float(self.features.get("c_puct", 0.4))\n        self.policy_temperature = float(self.features.get("policy_temperature", 10.0))\n        self.max_action_combinations = int(self.features.get("max_action_combinations", MAX_ACTION_COMBINATIONS))\n        if self.max_action_combinations <= 0:\n            raise ValueError("features.max_action_combinations must be greater than zero")\n        print(f"[MCTSTransformerAgent] SEARCH_COUNT={self.SEARCH_COUNT}", flush=True)\n        print(f"[MCTSTransformerAgent] Active Features: {self.features}", flush=True)\n\n    def get_deck(self) -> list[int]:\n        return self.deck\n\n    def act(self, obs_dict: dict) -> list[int]:\n        if not isinstance(obs_dict, dict) or obs_dict.get("select") is None:\n            return self.get_deck()\n        obs = to_observation_class(obs_dict)\n\n        your_index = obs.current.yourIndex\n        state = obs.current\n        active = state.players[1 - your_index].active\n        opponent = infer_opponent_hidden_cards(state, your_index, random)\n        search_state = search_begin(\n            obs,\n            your_deck=random.sample(self.deck, state.players[your_index].deckCount),\n            your_prize=random.sample(self.deck, len(state.players[your_index].prize)),\n            opponent_deck=opponent.deck,\n            opponent_prize=opponent.prize,\n            opponent_hand=opponent.hand,\n            opponent_active=[1072] if len(active) > 0 and active[0] is None else [],\n        )\n\n        evaluate = _nn_evaluator(self.model, self.deck)\n        root = create_node(\n            None,\n            search_state,\n            your_index,\n            evaluate,\n            c_puct=self.c_puct,\n            policy_temperature=self.policy_temperature,\n            max_action_combinations=self.max_action_combinations,\n        )\n        for _ in range(self.SEARCH_COUNT):\n            current = root\n            while True:\n                next_child = select_child(current, your_index, c_puct=self.c_puct)\n                if next_child is None:\n                    break\n                if next_child.node is None:\n                    s_state = search_step(current.state.searchId, next_child.select)\n                    next_child.node = create_node(\n                        current,\n                        s_state,\n                        your_index,\n                        evaluate,\n                        c_puct=self.c_puct,\n                        policy_temperature=self.policy_temperature,\n                        max_action_combinations=self.max_action_combinations,\n                    )\n                    break\n                current = next_child.node\n                if current.state.observation.current.result >= 0:\n                    current.backprop(current.value)\n                    break\n\n        max_child = None\n        max_visit = -1\n        for child in root.children:\n            if child.node is not None and max_visit < child.node.visit:\n                max_child = child\n                max_visit = child.node.visit\n\n        search_end()\n        if max_child is not None:\n            return max_child.select\n        return root.children[0].select if root.children else [0]\n\n\n_agent_instance = None\n\n\ndef _agent_dir() -> str:\n    module_file = globals().get("__file__")\n    if module_file:\n        return os.path.dirname(os.path.abspath(module_file))\n    return "/kaggle_simulations/agent"\n\n\ndef _default_model_path() -> str | None:\n    explicit = os.environ.get("MCTS_MODEL_PATH")\n    if explicit:\n        return explicit\n    base_dir = _agent_dir()\n    candidates = [\n        os.path.join(base_dir, "mcts.pth"),\n        os.path.join(os.getcwd(), "mcts.pth"),\n        "/kaggle_simulations/agent/mcts.pth",\n    ]\n    return next((p for p in candidates if os.path.exists(p)), None)\n\n\ndef agent(obs_dict: dict) -> list[int]:\n    global _agent_instance\n    if _agent_instance is None:\n        _agent_instance = MCTSTransformerAgent(\n            deck=os.environ.get("MCTS_DECK", "deck.csv"),\n            model_path=_default_model_path(),\n        )\n    return _agent_instance.act(obs_dict)\n'
os.makedirs(os.path.dirname(os.path.join(WORKING_DIR, "mcts/agent.py")), exist_ok=True)
with open(os.path.join(WORKING_DIR, "mcts/agent.py"), "w") as f:
    f.write(mcts_agent_py_content)

# Write helper: mcts/encoding.py
mcts_encoding_py_content = '"""Sparse state and action encoding for the MCTS policy/value network.\n\nThe state encoder emits 24 words: two players times eight bench words (sharing\npositions within each player\'s block), two active words, two player-state words,\nthen hand, own-deck, stadium, and misc words. Continuous scales are HP/400,\ndeck and discard counts/60, hand/8, bench/5, discarded cards weighted 0.25,\nand attached Energy weighted 0.5. The misc word contains turn and first-player\nfeatures.\n\nAction features start with 14 fixed slots, followed by the attack block at offset\n14, then card blocks sized ``(1 + 8 roles + 48 contexts) * card_count``.\n"""\n\ntry:\n    from base_agent import get_card as get_card_helper\nexcept ImportError:\n    from agents.base import get_card as get_card_helper\nfrom cg.api import Card, Observation, OptionType, PlayerState, Pokemon\n\nfrom .model import CARD_COUNT, DECODER_ATTACK_OFFSET, DECODER_CARD_OFFSET, DECODER_MAIN_FEATURE\n\n\nclass SparseVector:\n    def __init__(self) -> None:\n        self.index: list[int] = []\n        self.value: list[float] = []\n        self.offset: list[int] = []\n        self.pos = 0\n\n    def add(self, index: int, value: float | int | bool) -> None:\n        value = float(value)\n        if value != 0.0:\n            self.index.append(self.pos + index)\n            self.value.append(value)\n\n    def add_pos(self, pos: int) -> None:\n        self.pos += pos\n\n    def add_single(self, value: float | int | bool) -> None:\n        value = float(value)\n        if value != 0.0:\n            self.index.append(self.pos)\n            self.value.append(value)\n        self.pos += 1\n\n    def word_start(self) -> None:\n        self.offset.append(len(self.index))\n\n\ndef add_card(sv: SparseVector, card: Card | Pokemon | None) -> None:\n    if card is not None:\n        sv.add(card.id, 1)\n    sv.add_pos(CARD_COUNT)\n\n\ndef add_cards(sv: SparseVector, cards: list[Card] | None, value: float) -> None:\n    if cards is not None:\n        for card in cards:\n            sv.add(card.id, value)\n    sv.add_pos(CARD_COUNT)\n\n\ndef add_pokemon(sv: SparseVector, poke: Pokemon | None) -> None:\n    if poke is None:\n        sv.add_single(1)\n        sv.add_pos(1 + 3 * CARD_COUNT)\n    else:\n        sv.add_single(0)\n        sv.add_single(poke.hp / 400.0)\n        add_card(sv, poke)\n        add_cards(sv, poke.tools, 1.0)\n        add_cards(sv, poke.energyCards, 0.5)\n\n\ndef add_player(sv: SparseVector, ps: PlayerState) -> None:\n    sv.add_single(ps.deckCount / 60.0)\n    sv.add_single(len(ps.discard) / 60.0)\n    sv.add_single(ps.handCount / 8.0)\n    sv.add_single(len(ps.bench) / 5.0)\n    sv.add(len(ps.prize), 1)\n    sv.add_pos(7)\n\n    sv.add_single(ps.poisoned)\n    sv.add_single(ps.burned)\n    sv.add_single(ps.asleep)\n    sv.add_single(ps.paralyzed)\n    sv.add_single(ps.confused)\n    add_cards(sv, ps.discard, 0.25)\n\n\ndef encode_state(obs: Observation, your_deck: list[int]) -> SparseVector:\n    your_index = obs.current.yourIndex\n    state = obs.current\n\n    sv = SparseVector()\n    for i in range(2):\n        ps = state.players[i ^ your_index]\n        for j in range(8):\n            sv.word_start()\n            pos = sv.pos\n            if j < len(ps.bench):\n                add_pokemon(sv, ps.bench[j])\n            else:\n                add_pokemon(sv, None)\n            if j != 7:\n                sv.pos = pos\n\n    for i in range(2):\n        ps = state.players[i ^ your_index]\n        sv.word_start()\n        if ps.active:\n            add_pokemon(sv, ps.active[0])\n        else:\n            add_pokemon(sv, None)\n\n    for i in range(2):\n        ps = state.players[i ^ your_index]\n        sv.word_start()\n        add_player(sv, ps)\n\n    sv.word_start()\n    add_cards(sv, state.players[your_index].hand, 0.25)\n\n    sv.word_start()\n    for id in your_deck:\n        sv.add(id, 0.25)\n    sv.add_pos(CARD_COUNT)\n\n    sv.word_start()\n    add_cards(sv, state.stadium, 1.0)\n\n    sv.word_start()\n    sv.add_single(1)\n    sv.add_single(state.turn / 10.0)\n    sv.add_single(state.firstPlayer == your_index)\n    return sv\n\n\ndef add_role_card_feature(sv: SparseVector, feature_index: int, card: Card | Pokemon | None) -> None:\n    if card is not None:\n        sv.add(DECODER_CARD_OFFSET + feature_index * CARD_COUNT + card.id, 1)\n\n\ndef add_context_card_id(sv: SparseVector, context: int, card_id: int) -> None:\n    sv.add(DECODER_CARD_OFFSET + (DECODER_MAIN_FEATURE + context) * CARD_COUNT + card_id, 1)\n\n\ndef add_context_card(sv: SparseVector, context: int, card: Card | Pokemon | None) -> None:\n    if card is not None:\n        add_context_card_id(sv, context, card.id)\n\n\ndef encode_actions(obs: Observation, actions: list[list[int]]) -> SparseVector:\n    sv = SparseVector()\n    your_index = obs.current.yourIndex\n    ps = obs.current.players[your_index]\n    context = int(obs.select.context) if hasattr(obs.select.context, "value") else int(obs.select.context)\n\n    for action in actions:\n        sv.word_start()\n        if not action:\n            sv.add(0, 1)\n            continue\n\n        for i in action:\n            o = obs.select.option[i]\n            o_type = int(o.type) if hasattr(o.type, "value") else int(o.type)\n            if o_type == OptionType.END:\n                sv.add(1, 1)\n            elif o_type == OptionType.YES:\n                sv.add(2, 1)\n            elif o_type == OptionType.NO:\n                sv.add(3, 1)\n            elif o_type == OptionType.SPECIAL_CONDITION:\n                sv.add(4 + int(o.specialConditionType), 1)\n            elif o_type == OptionType.NUMBER:\n                sv.add(9 + min(o.number, 4), 1)\n            elif o_type == OptionType.ATTACK:\n                sv.add(DECODER_ATTACK_OFFSET + o.attackId, 1)\n            elif o_type == OptionType.PLAY:\n                add_role_card_feature(sv, 0, ps.hand[o.index] if ps.hand else None)\n            elif o_type == OptionType.ATTACH:\n                add_role_card_feature(sv, 1, get_card_helper(obs, int(o.area), o.index, your_index))\n                add_role_card_feature(sv, 2, get_card_helper(obs, int(o.inPlayArea), o.inPlayIndex, your_index))\n            elif o_type == OptionType.EVOLVE:\n                add_role_card_feature(sv, 3, get_card_helper(obs, int(o.area), o.index, your_index))\n                add_role_card_feature(sv, 4, get_card_helper(obs, int(o.inPlayArea), o.inPlayIndex, your_index))\n            elif o_type == OptionType.ABILITY:\n                add_role_card_feature(sv, 5, get_card_helper(obs, int(o.area), o.index, your_index))\n            elif o_type == OptionType.DISCARD:\n                add_role_card_feature(sv, 6, get_card_helper(obs, int(o.area), o.index, your_index))\n            elif o_type == OptionType.RETREAT:\n                add_role_card_feature(sv, 7, ps.active[0] if ps.active else None)\n            elif o_type == OptionType.CARD:\n                add_context_card(sv, context, get_card_helper(obs, int(o.area), o.index, o.playerIndex))\n            elif o_type == OptionType.TOOL_CARD:\n                card = get_card_helper(obs, int(o.area), o.index, o.playerIndex)\n                if card and hasattr(card, "tools") and o.toolIndex < len(card.tools):\n                    add_context_card(sv, context, card.tools[o.toolIndex])\n            elif o_type in (OptionType.ENERGY_CARD, OptionType.ENERGY):\n                card = get_card_helper(obs, int(o.area), o.index, o.playerIndex)\n                if card and hasattr(card, "energyCards") and o.energyIndex < len(card.energyCards):\n                    add_context_card(sv, context, card.energyCards[o.energyIndex])\n            elif o_type == OptionType.SKILL:\n                add_context_card_id(sv, context, o.cardId)\n    return sv\n'
os.makedirs(os.path.dirname(os.path.join(WORKING_DIR, "mcts/encoding.py")), exist_ok=True)
with open(os.path.join(WORKING_DIR, "mcts/encoding.py"), "w") as f:
    f.write(mcts_encoding_py_content)

# Write helper: mcts/model.py
mcts_model_py_content = '"""Transformer policy/value model for sparse Pokémon TCG observations.\n\nThe value path uses an EmbeddingBag sparse input, transformer encoder, and scalar\nvalue head. The policy path uses a decoder EmbeddingBag and cross-attention layers\nover the encoded state before its scalar action head. ``MODEL_ARGS`` contains\n``(d_model, num_heads, d_feedforward, encoder_layers, decoder_layers)``;\n``num_heads`` must divide ``d_model``.\n"""\n\nimport torch\n\nfrom cg.api import all_attack, all_card_data\n\n\ndef _load_feature_counts() -> tuple[int, int]:\n    try:\n        cards = all_card_data()\n        return max(cards, key=lambda card: card.cardId).cardId + 1, max(\n            all_attack(), key=lambda attack: attack.attackId\n        ).attackId + 1\n    except Exception:\n        return 2000, 2000\n\n\nCARD_COUNT, ATTACK_COUNT = _load_feature_counts()\n\nNUM_WORDS_ENCODER = 24\nENCODER_SIZE = 22000\nDECODER_MAIN_FEATURE = 8\nDECODER_ATTACK_OFFSET = 14\nDECODER_CARD_OFFSET = DECODER_ATTACK_OFFSET + ATTACK_COUNT\nDECODER_SIZE = DECODER_CARD_OFFSET + (1 + DECODER_MAIN_FEATURE + 48) * CARD_COUNT\n\n# (d_model, num_heads, d_feedforward, n_encoder_layers, n_decoder_layers).\n# Single source of truth: training and inference both build PolicyValueNet\n# from this, so checkpoints always match. num_heads must divide d_model.\nMODEL_ARGS = (256, 4, 512, 2, 2)\n\n\ndef _layer_count(state_dict: dict, prefix: str, suffix: str) -> int:\n    found = []\n    for key in state_dict:\n        if key.startswith(prefix) and key.endswith(suffix):\n            try:\n                found.append(int(key[len(prefix) :].split(".", 1)[0]))\n            except ValueError:\n                pass\n    return max(found) + 1 if found else 0\n\n\ndef model_args_from_state_dict(state_dict: dict) -> tuple[int, int, int, int, int]:\n    d_model = int(state_dict["encoder_bag.weight"].shape[1])\n    d_feedforward = int(state_dict["encoder.layers.0.linear1.weight"].shape[0])\n    num_heads = MODEL_ARGS[1] if d_model % MODEL_ARGS[1] == 0 else 4\n    return (\n        d_model,\n        num_heads,\n        d_feedforward,\n        _layer_count(state_dict, "encoder.layers.", ".linear1.weight"),\n        _layer_count(state_dict, "decoder.", ".fc1.weight"),\n    )\n\n\nclass DecoderLayer(torch.nn.Module):\n    def __init__(self, d_model: int, num_heads: int, d_feedforward: int) -> None:\n        super().__init__()\n        self.attention = torch.nn.MultiheadAttention(d_model, num_heads)\n        self.fc1 = torch.nn.Linear(d_model, d_feedforward)\n        self.fc2 = torch.nn.Linear(d_feedforward, d_model)\n        self.norm1 = torch.nn.LayerNorm(d_model)\n        self.norm2 = torch.nn.LayerNorm(d_model)\n\n    def forward(self, x: torch.Tensor, encoder_out: torch.Tensor) -> torch.Tensor:\n        y, _ = self.attention(x, encoder_out, encoder_out, need_weights=False)\n        res = self.norm1(x + y)\n        y = self.fc1(res)\n        y = torch.nn.functional.relu(y)\n        y = self.fc2(y)\n        return self.norm2(res + y)\n\n\nclass PolicyValueNet(torch.nn.Module):\n    def __init__(\n        self, d_model: int, num_heads: int, d_feedforward: int, num_layers_encoder: int, num_layers_decoder: int\n    ) -> None:\n        super().__init__()\n        self.d_model = d_model\n        self.encoder_bag = torch.nn.EmbeddingBag(ENCODER_SIZE, d_model, mode="sum")\n        encoder_layer = torch.nn.TransformerEncoderLayer(d_model, num_heads, d_feedforward, 0)\n        self.encoder = torch.nn.TransformerEncoder(encoder_layer, num_layers_encoder, enable_nested_tensor=False)\n        self.encoder_fc = torch.nn.Linear(d_model, 1)\n        self.decoder_bag = torch.nn.EmbeddingBag(DECODER_SIZE, d_model, mode="sum")\n        self.decoder = torch.nn.ModuleList()\n        for _ in range(num_layers_decoder):\n            self.decoder.append(DecoderLayer(d_model, num_heads, d_feedforward))\n        self.decoder_fc = torch.nn.Linear(d_model, 1)\n\n    def forward(\n        self,\n        index_encoder: torch.Tensor,\n        value_encoder: torch.Tensor,\n        offset_encoder: torch.Tensor,\n        index_decoder: torch.Tensor,\n        value_decoder: torch.Tensor,\n        offset_decoder: torch.Tensor,\n    ) -> tuple[torch.Tensor, torch.Tensor]:\n        v = self.encoder_bag(index_encoder, offset_encoder, value_encoder)\n        v = v.reshape(-1, NUM_WORDS_ENCODER, self.d_model).transpose(0, 1)\n        batch_size = v.size(1)\n        encoder_out = self.encoder(v)\n        v = self.encoder_fc(encoder_out)\n        v = torch.tanh(v.mean(0))\n\n        p = self.decoder_bag(index_decoder, offset_decoder, value_decoder)\n        p = p.reshape(batch_size, -1, self.d_model).transpose(0, 1)\n        for layer in self.decoder:\n            p = layer(p, encoder_out)\n        p = self.decoder_fc(p)\n        p = p.transpose(0, 1).view(batch_size, -1)\n        p = torch.tanh(p)\n        return (v, p)\n\n\nMyModel = PolicyValueNet\n'
os.makedirs(os.path.dirname(os.path.join(WORKING_DIR, "mcts/model.py")), exist_ok=True)
with open(os.path.join(WORKING_DIR, "mcts/model.py"), "w") as f:
    f.write(mcts_model_py_content)

# Write helper: mcts/opponent.py
mcts_opponent_py_content = '"""Opponent archetype detection and hidden-card determinization."""\n\nfrom __future__ import annotations\n\nfrom collections import Counter\nfrom dataclasses import dataclass\nfrom typing import Protocol, TypeVar\n\nfrom cg.api import State\n\nARCHETYPE_DECKS: dict[str, tuple[int, ...]] = {\n    "abomasnow": (\n        721,\n        721,\n        722,\n        722,\n        722,\n        722,\n        723,\n        723,\n        723,\n        723,\n        1121,\n        1121,\n        1121,\n        1121,\n        1126,\n        1192,\n        1192,\n        1192,\n        1192,\n        1227,\n        1227,\n        1227,\n        1227,\n        1262,\n        1262,\n        1262,\n        *([3] * 34),\n    ),\n    "dragapult": (\n        119,\n        119,\n        119,\n        119,\n        120,\n        120,\n        120,\n        120,\n        121,\n        121,\n        121,\n        140,\n        184,\n        235,\n        235,\n        1071,\n        1079,\n        1079,\n        1080,\n        1086,\n        1086,\n        1086,\n        1086,\n        1097,\n        1097,\n        1120,\n        1120,\n        1120,\n        1120,\n        1121,\n        1121,\n        1121,\n        1121,\n        1152,\n        1152,\n        1152,\n        1156,\n        1182,\n        1182,\n        1182,\n        1198,\n        1198,\n        1198,\n        1198,\n        1210,\n        1210,\n        1227,\n        1227,\n        1227,\n        1227,\n        1256,\n        1256,\n        2,\n        2,\n        2,\n        2,\n        5,\n        5,\n        5,\n        5,\n    ),\n    "dragapult_blaziken": (\n        119,\n        119,\n        119,\n        119,\n        120,\n        120,\n        120,\n        120,\n        121,\n        121,\n        324,\n        324,\n        325,\n        326,\n        326,\n        235,\n        235,\n        112,\n        112,\n        31,\n        140,\n        272,\n        1071,\n        1227,\n        1227,\n        1227,\n        1227,\n        1182,\n        1182,\n        1182,\n        1198,\n        1198,\n        1231,\n        1086,\n        1086,\n        1086,\n        1086,\n        1121,\n        1121,\n        1121,\n        1121,\n        1152,\n        1152,\n        1152,\n        1079,\n        1079,\n        1079,\n        1097,\n        1097,\n        1080,\n        1256,\n        1260,\n        5,\n        5,\n        5,\n        2,\n        2,\n        2,\n        7,\n        7,\n    ),\n    "zacian": (\n        336,\n        336,\n        336,\n        336,\n        1205,\n        1205,\n        1205,\n        1205,\n        1227,\n        1227,\n        1227,\n        1227,\n        1235,\n        1235,\n        1235,\n        1235,\n        1182,\n        1182,\n        1198,\n        1198,\n        1121,\n        1121,\n        1121,\n        1121,\n        1123,\n        1123,\n        1123,\n        1123,\n        1122,\n        1122,\n        1122,\n        1122,\n        1158,\n        1097,\n        1097,\n        1118,\n        1118,\n        1140,\n        1140,\n        1140,\n        1116,\n        1116,\n        1116,\n        1139,\n        1139,\n        1139,\n        *([8] * 14),\n    ),\n    "lucario": (\n        673,\n        673,\n        673,\n        674,\n        674,\n        674,\n        675,\n        675,\n        676,\n        676,\n        676,\n        677,\n        677,\n        677,\n        677,\n        678,\n        678,\n        678,\n        678,\n        1102,\n        1102,\n        1102,\n        1102,\n        1123,\n        1123,\n        1123,\n        1141,\n        1141,\n        1142,\n        1142,\n        1142,\n        1152,\n        1152,\n        1152,\n        1152,\n        1159,\n        1182,\n        1182,\n        1192,\n        1192,\n        1192,\n        1192,\n        1227,\n        1227,\n        1227,\n        1252,\n        1252,\n        *([6] * 13),\n    ),\n}\n\nSIGNATURE_MAP = {\n    **dict.fromkeys((3, 721, 722, 723, 1126, 1262), "abomasnow"),\n    **dict.fromkeys((8, 336, 1116, 1118, 1122, 1139, 1140, 1158, 1205, 1235), "zacian"),\n    **dict.fromkeys((6, 673, 674, 675, 676, 677, 678, 1102, 1141, 1142, 1159, 1252), "lucario"),\n    **dict.fromkeys((184, 1120, 1156, 1210), "dragapult"),\n    **dict.fromkeys((7, 31, 112, 272, 324, 325, 326, 1231, 1260), "dragapult_blaziken"),\n    **dict.fromkeys((2, 5, 119, 120, 121, 140, 235, 1071, 1079, 1080, 1086, 1256), "dragapult_any"),\n}\n\n\nT = TypeVar("T")\n\n\nclass RandomSource(Protocol):\n    def choice(self, sequence: list[T]) -> T: ...\n    def choices(self, population: tuple[T, ...], *, k: int) -> list[T]: ...\n    def shuffle(self, values: list[T]) -> None: ...\n\n\n@dataclass(frozen=True)\nclass OpponentHiddenCards:\n    archetype: str\n    deck: list[int]\n    prize: list[int]\n    hand: list[int]\n\n\ndef _revealed_cards(state: State, opponent_index: int) -> tuple[list[int], list[int]]:\n    opponent = state.players[opponent_index]\n    visible: list[int] = []\n    for pokemon in [*(opponent.active or []), *(opponent.bench or [])]:\n        if pokemon is not None:\n            visible.append(pokemon.id)\n            visible.extend(card.id for card in (pokemon.tools or []) if card is not None)\n            visible.extend(card.id for card in (pokemon.energyCards or []) if card is not None)\n    visible.extend(card.id for card in (opponent.discard or []) if card is not None)\n    voting = [*visible, *(card.id for card in (state.stadium or []) if card is not None)]\n    return visible, voting\n\n\ndef infer_opponent_hidden_cards(state: State, your_index: int, rng: RandomSource) -> OpponentHiddenCards:\n    """Infer an opponent archetype and sample its unseen hand, prizes, and deck."""\n    opponent = state.players[1 - your_index]\n    visible, voting = _revealed_cards(state, 1 - your_index)\n    votes = dict.fromkeys(ARCHETYPE_DECKS, 0)\n    for card_id in voting:\n        if (archetype := SIGNATURE_MAP.get(card_id)) == "dragapult_any":\n            votes["dragapult"] += 1\n            votes["dragapult_blaziken"] += 1\n        elif archetype is not None:\n            votes[archetype] += 1\n\n    max_votes = max(votes.values())\n    candidates = [name for name, count in votes.items() if count == max_votes] if max_votes else list(votes)\n    archetype = rng.choice(candidates)\n    full_deck = ARCHETYPE_DECKS[archetype]\n    remaining = list((Counter(full_deck) - Counter(visible)).elements())\n    needed = opponent.deckCount + len(opponent.prize) + opponent.handCount\n    if len(remaining) < needed:\n        remaining.extend(rng.choices(full_deck, k=needed - len(remaining)))\n    elif len(remaining) > needed:\n        remaining = remaining[:needed]\n    rng.shuffle(remaining)\n    hand_end, prize_end = opponent.handCount, opponent.handCount + len(opponent.prize)\n    return OpponentHiddenCards(archetype, remaining[prize_end:], remaining[hand_end:prize_end], remaining[:hand_end])\n'
os.makedirs(os.path.dirname(os.path.join(WORKING_DIR, "mcts/opponent.py")), exist_ok=True)
with open(os.path.join(WORKING_DIR, "mcts/opponent.py"), "w") as f:
    f.write(mcts_opponent_py_content)

# Write helper: mcts/search.py
mcts_search_py_content = '"""Shared MCTS tree mechanics.\n\nSelection is PUCT-style: ``q + 0.4*sqrt(N_parent)*prior/(1+n)``. Priors use\n``exp(policy*10)`` and candidate combinations are capped at 64 to bound inference\nlatency on large multi-select prompts. Values use the root player\'s perspective:\n+1 is a win for ``your_index`` and values are negated at opponent-to-move nodes.\n\nInference determinizes hidden information on every move: the agent samples its own\nunknown deck and Prize cards, while unknown opponent cards use Snorlax card 1072 as\na filler. That determinization is prepared by ``agent.py`` before this module builds\nthe search tree.\n"""\n\nimport math\nfrom collections.abc import Callable\n\nimport torch\n\nfrom cg.api import Observation, SearchState\n\nfrom .encoding import SparseVector\nfrom .model import PolicyValueNet\n\n# The cg API exposes match results as raw integers: player 0, player 1, or draw.\nRESULT_DRAW = 2\nEXPLORATION_C = 0.4\nPOLICY_TEMPERATURE = 10.0\nMAX_ACTION_COMBINATIONS = 64\n\n\ndef evaluate_position(sv_enc: SparseVector, sv_dec: SparseVector, model: PolicyValueNet) -> tuple[float, list[float]]:\n    device = next(model.parameters()).device\n    with torch.no_grad():\n        value, policy = model(\n            torch.tensor(sv_enc.index, dtype=torch.int32, device=device),\n            torch.tensor(sv_enc.value, dtype=torch.float32, device=device),\n            torch.tensor(sv_enc.offset, dtype=torch.int32, device=device),\n            torch.tensor(sv_dec.index, dtype=torch.int32, device=device),\n            torch.tensor(sv_dec.value, dtype=torch.float32, device=device),\n            torch.tensor(sv_dec.offset, dtype=torch.int32, device=device),\n        )\n    return (value.tolist()[0][0], policy.tolist()[0])\n\n\nclass Child:\n    def __init__(self, select: list[int], prob: float) -> None:\n        self.node = None\n        self.select = select\n        self.prob = prob\n\n\nclass Node:\n    def __init__(self, parent: "Node | None", state: SearchState) -> None:\n        self.value = -2.0\n        self.total = 0.0\n        self.visit = 0\n        self.parent = parent\n        self.children = []\n        self.state = state\n\n    def backprop(self, value: float) -> None:\n        self.total += value\n        self.visit += 1\n        if self.parent is not None:\n            self.parent.backprop(value)\n\n\ndef enumerate_action_combinations(\n    max_count: int, num_options: int, cap: int = MAX_ACTION_COMBINATIONS\n) -> list[list[int]]:\n    """Enumerate index combinations of size `max_count` from `num_options` options.\n\n    Combinations are generated in lexicographic order (each a sorted list of distinct\n    indices in `range(num_options)`), and generation stops once `cap` combinations have\n    been produced.\n    """\n    if max_count > num_options:\n        max_count = num_options\n    if max_count < 0 or cap <= 0 or (num_options == 0 and max_count > 0):\n        return []\n    actions = []\n    indices = list(range(max_count))\n    for _ in range(cap):\n        actions.append(indices.copy())\n        for i in range(len(indices)):\n            index = len(indices) - i - 1\n            if indices[index] < num_options - i - 1:\n                indices[index] += 1\n                for j in range(index + 1, len(indices)):\n                    indices[j] = indices[j - 1] + 1\n                break\n        else:\n            break\n    return actions\n\n\ndef build_children(\n    node: Node, actions: list[list[int]], policy: list[float], policy_temperature: float = POLICY_TEMPERATURE\n) -> None:\n    """Attach softmax-weighted children to a node from a policy vector."""\n    total_prob = 0.0\n    for i in range(len(policy)):\n        p = math.exp(policy[i] * policy_temperature)\n        node.children.append(Child(actions[i], p))\n        total_prob += p\n    for c in node.children:\n        c.prob /= total_prob\n\n\ndef select_child(current: Node, your_index: int, c_puct: float = EXPLORATION_C) -> Child | None:\n    """UCB-select the best child of ``current`` (None if it has none)."""\n    best, chosen = -1e18, None\n    c = c_puct * math.sqrt(current.visit)\n    flip = current.state.observation.current.yourIndex != your_index\n    for child in current.children:\n        if child.node is None:\n            q = current.total / current.visit\n            visit = 0\n        else:\n            q = child.node.total / child.node.visit\n            visit = child.node.visit\n        if flip:\n            q = -q\n        u = q + c * child.prob / (1 + visit)\n        if u > best:\n            best, chosen = u, child\n    return chosen\n\n\nEvaluator = Callable[[Observation, list[list[int]]], tuple[float, list[float]]]\n\n\ndef create_node(\n    parent: Node | None,\n    search_state: SearchState,\n    your_index: int,\n    evaluate: Evaluator,\n    c_puct: float = EXPLORATION_C,\n    policy_temperature: float = POLICY_TEMPERATURE,\n    max_action_combinations: int = MAX_ACTION_COMBINATIONS,\n) -> Node:\n    if max_action_combinations <= 0:\n        raise ValueError("max_action_combinations must be greater than zero")\n    node = Node(parent, search_state)\n    obs = search_state.observation\n    state = obs.current\n\n    if state.result >= 0:\n        if state.result == RESULT_DRAW:\n            node.value = 0.0\n        elif state.result == your_index:\n            node.value = 1.0\n        else:\n            node.value = -1.0\n        node.backprop(node.value)\n    else:\n        actions = enumerate_action_combinations(\n            obs.select.maxCount,\n            len(obs.select.option),\n            cap=max_action_combinations,\n        )\n        value, policy = evaluate(obs, actions)\n        v = value\n        if state.yourIndex != your_index:\n            v = -v\n        node.value = v\n        node.backprop(v)\n        build_children(node, actions, policy, policy_temperature=policy_temperature)\n    return node\n'
os.makedirs(os.path.dirname(os.path.join(WORKING_DIR, "mcts/search.py")), exist_ok=True)
with open(os.path.join(WORKING_DIR, "mcts/search.py"), "w") as f:
    f.write(mcts_search_py_content)

# Copy cg directory
import glob


def find_cg_dir():
    candidates = [
        "/kaggle/input/pokemon-tcg-ai-battle/sample_submission/cg",
        "/kaggle/input/competitions/pokemon-tcg-ai-battle/sample_submission/cg",
        "/kaggle/input/**/sample_submission/cg",
        "/kaggle/input/**/cg",
    ]
    for pattern in candidates:
        for path in glob.glob(pattern, recursive=True):
            if os.path.isdir(path) and os.path.exists(os.path.join(path, "api.py")):
                return path
    raise FileNotFoundError("Could not find the official cg SDK directory.")


try:
    cg_src = find_cg_dir()
    cg_dst = os.path.join(WORKING_DIR, "cg")
    if os.path.exists(cg_dst):
        shutil.rmtree(cg_dst)
    shutil.copytree(cg_src, cg_dst, ignore=shutil.ignore_patterns("__pycache__", "*.pyc", "*.pyo"))
except Exception as e:
    print(f"Error copying cg: {e}")

# Create submission.tar.gz
# If there is a model weights file in the competition input or attached weight
# dataset, copy it into the submission archive.
for root, dirs, files in os.walk("/kaggle/input"):
    for file in files:
        if file in ("mcts.pth", "mcts_model.pth"):
            shutil.copy(os.path.join(root, file), os.path.join(WORKING_DIR, "mcts.pth"))
            break

submission_path = os.path.join(WORKING_DIR, "submission.tar.gz")


def submission_tar_filter(info):
    parts = info.name.split("/")
    if "__pycache__" in parts or info.name.endswith((".pyc", ".pyo")):
        return None
    return info


with tarfile.open(submission_path, "w:gz") as tar:
    items = ["main.py", "deck.csv", "cg"] + [
        "base_agent.py",
        "mcts/__init__.py",
        "mcts/agent.py",
        "mcts/encoding.py",
        "mcts/model.py",
        "mcts/opponent.py",
        "mcts/search.py",
    ]
    if os.path.exists(os.path.join(WORKING_DIR, "mcts.pth")):
        items.append("mcts.pth")
    if os.path.exists(os.path.join(WORKING_DIR, "variant.toml")):
        items.append("variant.toml")
    for item in items:
        full_path = os.path.join(WORKING_DIR, item)
        if os.path.exists(full_path):
            tar.add(full_path, arcname=item, filter=submission_tar_filter)

print(f"Created {submission_path}")
print(f"Size: {os.path.getsize(submission_path)} bytes")

# Verify contents
with tarfile.open(submission_path, "r:gz") as tar:
    print("Contents:")
    for member in tar.getmembers():
        print(f"  {member.name} ({member.size} bytes)")
